import fs from 'node:fs/promises';
import path from 'node:path';

const SUPABASE_URL = 'https://batyczeeyeoqjuxhhlic.supabase.co';
const SUPABASE_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJhdHljemVleWVvcWp1eGhobGljIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzA4MDM1NDMsImV4cCI6MjA4NjM3OTU0M30.obSL3nHGuvaB-bW3-mjiJceGNrI6jsT6PZZrTdWsqQI';

const OUT_DIR = path.resolve('cache');
const OUT_FILE = path.join(OUT_DIR, 'builderz-kb-cache.json');

const headers = {
  apikey: SUPABASE_ANON_KEY,
  Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
};

function compactText(text = '') {
  return text.replace(/\s+/g, ' ').trim();
}

function excerpt(text = '', max = 1200) {
  const c = compactText(text);
  return c.length > max ? `${c.slice(0, max)}…` : c;
}

async function fetchKbRows() {
  const url = `${SUPABASE_URL}/rest/v1/knowledge_base?select=id,category,title,content,url,created_at&order=created_at.desc.nullslast`;
  const res = await fetch(url, { headers });
  if (!res.ok) throw new Error(`KB fetch failed: ${res.status} ${await res.text()}`);
  return res.json();
}

async function fetchUrlSummary(url) {
  try {
    const res = await fetch(url, { redirect: 'follow' });
    if (!res.ok) {
      return { ok: false, status: res.status, summary: '' };
    }
    const html = await res.text();
    const noScript = html
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&');

    return {
      ok: true,
      status: res.status,
      summary: excerpt(noScript, 1800),
    };
  } catch (err) {
    return { ok: false, status: 0, summary: '', error: String(err?.message || err) };
  }
}

async function main() {
  const rows = await fetchKbRows();
  const navigationRows = rows.filter((r) => r?.category === 'navigation' && r?.url);

  const pageSummaries = {};
  for (const row of navigationRows) {
    if (!pageSummaries[row.url]) {
      pageSummaries[row.url] = await fetchUrlSummary(row.url);
    }
  }

  const contacts = {
    email: 'hello@builderz.dev',
    contactPage: 'https://builderz.dev/contact',
    calendly: 'https://calendly.com/builderz-agency',
    x: 'https://x.com/builderzdotdev',
    linkedin: 'https://www.linkedin.com/company/builderz-web3/',
    whatsapp: 'https://wa.me/971526426319',
  };

  const cache = {
    meta: {
      generatedAt: new Date().toISOString(),
      source: 'supabase+navigation-url-summaries',
      rowCount: rows.length,
      navigationUrlCount: navigationRows.length,
    },
    contacts,
    rows,
    pageSummaries,
  };

  await fs.mkdir(OUT_DIR, { recursive: true });
  await fs.writeFile(OUT_FILE, JSON.stringify(cache, null, 2), 'utf8');
  console.log(`Cache updated: ${OUT_FILE}`);
  console.log(`Rows: ${rows.length} | Navigation URLs: ${navigationRows.length}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});

